def solve(n: int) -> str:
    n_squared = n ** 2
    n_cubed = n ** 3

    hex_part = hex(n_squared)[2:].upper()

    def int_to_base36(num: int) -> str:
        if num == 0:
            return "0"
        digits = []
        while num > 0:
            remainder = num % 36
            if remainder < 10:
                digits.append(str(remainder))
            else:
                digits.append(chr(ord('A') + remainder - 10))
            num = num // 36
        return ''.join(reversed(digits))

    base36_part = int_to_base36(n_cubed)

    return hex_part + base36_part
